Create `app/schema/furigana.ts` with Zod-backed token contracts:

```typescript
import * as z from 'zod';

export const TextTokenSchema = z.object({
  type: z.literal('text').readonly(),
  value: z.string().regex(/^(?:[^{}])*$/, 'TextToken value must not contain {…} placeholders'),
});

export const RubyTokenSchema = z.object({
  type: z.literal('ruby').readonly(),
  kanji: z.string().min(1),
  reading: z.string().min(1),
});

export const FuriganaTokenSchema = z.discriminatedUnion('type', [
  TextTokenSchema,
  RubyTokenSchema,
]);

export type TextToken = z.infer<typeof TextTokenSchema>;
export type RubyToken = z.infer<typeof RubyTokenSchema>;
export type FuriganaToken = z.infer<typeof FuriganaTokenSchema>;

export function isTextToken(token: FuriganaToken): token is TextToken {
  return token.type === 'text';
}

export function isRubyToken(token: FuriganaToken): token is RubyToken {
  return token.type === 'ruby';
}
```

This keeps runtime validation and type inference in sync and establishes `~/schema/furigana` as the contract for downstream modules.

Create `app/lib/furigana/parser.ts`:

```typescript
// app/lib/furigana/parser.ts
import type { FuriganaToken } from './types';

/**
 * Parses an annotation string in the format "漢字{よみ}" into a typed token array.
 * 
 * Algorithm:
 * 1. Iterate through the string character by character
 * 2. Accumulate characters until encountering '{'
 * 3. On '{': extract preceding kanji (non-brace chars since last token), start reading accumulator
 * 4. On '}': create RubyToken from kanji + reading, reset accumulators
 * 5. Handle malformed input gracefully (unclosed braces become text)
 */
export function parseAnnotationString(input: string): FuriganaToken[] {
  const tokens: FuriganaToken[] = [];
  let textBuffer = '';
  let readingBuffer = '';
  let insideBraces = false;
  let kanjiStart = 0;

  for (let i = 0; i < input.length; i++) {
    const char = input[i];
    if (char === undefined) continue; // noUncheckedIndexedAccess guard

    if (char === '{' && !insideBraces) {
      insideBraces = true;
      // Find where the kanji starts (after last token or start)
      // All text before '{' that hasn't been tokenized yet is the kanji
      kanjiStart = textBuffer.length;
      continue;
    }

    if (char === '}' && insideBraces) {
      insideBraces = false;
      // Extract kanji from the end of textBuffer
      const kanji = textBuffer.slice(kanjiStart);
      const precedingText = textBuffer.slice(0, kanjiStart);

      if (precedingText) {
        tokens.push({ type: 'text', value: precedingText });
      }

      if (kanji || readingBuffer) {
        tokens.push({ type: 'ruby', kanji, reading: readingBuffer });
      }

      textBuffer = '';
      readingBuffer = '';
      kanjiStart = 0;
      continue;
    }

    if (insideBraces) {
      readingBuffer += char;
    } else {
      textBuffer += char;
    }
  }

  // Handle unclosed braces - treat as plain text
  if (insideBraces) {
    textBuffer += '{' + readingBuffer;
  }

  // Flush remaining text buffer
  if (textBuffer) {
    tokens.push({ type: 'text', value: textBuffer });
  }

  return tokens;
}
```

Key implementation notes:
- Uses character-by-character iteration (handles `noUncheckedIndexedAccess`)
- Never throws on malformed input
- Unclosed `{` treated as literal text
- Empty readings produce RubyToken with empty `reading` string
- No HTML in output - pure string values only

