```typescript
import { describe, it, expect } from 'vitest';
import { parseAnnotationString } from './parser';

describe('parseAnnotationString', () => {
  it('parses a single kanji compound with reading', () => {
    const result = parseAnnotationString('日本語{にほんご}');
    expect(result).toEqual([
      { type: 'ruby', kanji: '日本語', reading: 'にほんご' },
    ]);
  });

  it('parses kanji in the middle of hiragana text', () => {
    const result = parseAnnotationString('行{い}きました');
    expect(result).toEqual([
      { type: 'ruby', kanji: '行', reading: 'い' },
      { type: 'text', value: 'きました' },
    ]);
  });

  it('parses multiple consecutive ruby tokens', () => {
    const result = parseAnnotationString('東京{とうきょう}に行{い}きました');
    expect(result).toEqual([
      { type: 'ruby', kanji: '東京', reading: 'とうきょう' },
      { type: 'text', value: 'に' },
      { type: 'ruby', kanji: '行', reading: 'い' },
      { type: 'text', value: 'きました' },
    ]);
  });

  it('parses text with mixed kanji, hiragana, and punctuation', () => {
    const result = parseAnnotationString('東京{とうきょう}は元気{げんき}？');
    expect(result).toEqual([
      { type: 'ruby', kanji: '東京', reading: 'とうきょう' },
      { type: 'text', value: 'は' },
      { type: 'ruby', kanji: '元気', reading: 'げんき' },
      { type: 'text', value: '？' },
    ]);
  });

  it('returns a single text token for pure hiragana input', () => {
    const result = parseAnnotationString('こんにちは');
    expect(result).toEqual([{ type: 'text', value: 'こんにちは' }]);
  });

  it('returns a single text token for pure romaji input', () => {
    const result = parseAnnotationString('Hello world');
    expect(result).toEqual([{ type: 'text', value: 'Hello world' }]);
  });

  it('returns an empty array for empty string input', () => {
    const result = parseAnnotationString('');
    expect(result).toEqual([]);
  });

  it('handles consecutive ruby tokens with no text between them', () => {
    const result = parseAnnotationString('漢字{かんじ}漢字{かんじ}');
    expect(result).toEqual([
      { type: 'ruby', kanji: '漢字', reading: 'かんじ' },
      { type: 'ruby', kanji: '漢字', reading: 'かんじ' },
    ]);
  });

  it('handles unclosed opening brace - treats as text', () => {
    const result = parseAnnotationString('unclosed{');
    expect(result).toEqual([{ type: 'text', value: 'unclosed{' }]);
  });

  it('handles nested braces - does not crash', () => {
    const result = parseAnnotationString('bad{nested{braces}}');
    // Implementation-defined behavior: should not crash
    expect(result).toBeDefined();
    expect(Array.isArray(result)).toBe(true);
  });

  it('handles empty reading braces {}', () => {
    const result = parseAnnotationString('text{}');
    expect(result).toEqual([
      { type: 'ruby', kanji: 'text', reading: '' },
    ]);
  });

  it('handles input that is only braces {}', () => {
    const result = parseAnnotationString('{}');
    expect(result).toEqual([{ type: 'ruby', kanji: '', reading: '' }]);
  });

  it('handles multi-character readings', () => {
    const result = parseAnnotationString('勉強{べんきょう}');
    expect(result).toEqual([
      { type: 'ruby', kanji: '勉強', reading: 'べんきょう' },
    ]);
  });

  it('produces no HTML in token values', () => {
    const result = parseAnnotationString('<script>{alert}</script>');
    result.forEach(token => {
      if (token.type === 'text') {
        expect(token.value).not.toContain('<script>');
      }
    });
  });
});
```

