// app/lib/ai/client.ts
// Server-only — do not import from client-side modules

import OpenAI from 'openai';

const apiKey = process.env['OPENAI_API_KEY'];

if (!apiKey) {
  throw new Error(
    'OPENAI_API_KEY environment variable is required. ' +
    'Set it in your .env file or environment.',
  );
}

/**
 * Pre-configured OpenAI client instance for server-side use only.
 * Uses GPT-4o-mini for furigana generation.
 */
export const openaiClient = new OpenAI({ apiKey });
```

Key implementation notes:
- Uses bracket notation `process.env['OPENAI_API_KEY']` to satisfy `noPropertyAccessFromIndexSignature`
- Throws at module import time if key is missing (fail-fast pattern)
- No VITE_ prefix ensures this is server-only
- OpenAI SDK v6.31.0 auto-types responses; no `as` casts needed
- This module must NEVER be imported in client-side code (routes/*.tsx client portions, entry.client.tsx)

The module should be placed in `app/lib/ai/` which is a server-accessible path in React Router's SSR architecture.

Rewrite `app/routes/home.tsx` action function:

```typescript
// app/routes/home.tsx
import type { Route } from './+types/home';
import { openaiClient } from '~/lib/ai/client';
import { FURIGANA_SYSTEM_PROMPT, buildUserMessage } from '~/lib/ai/prompts';
import { parseAnnotationString } from '~/lib/furigana/parser';
import type { FuriganaToken } from '~/lib/furigana/types';

// Action return types
export type ActionSuccess = {
  tokens: FuriganaToken[];
};

export type ActionError = {
  error: string;
  originalText: string;
};

export type ActionData = ActionSuccess | ActionError;

const MAX_CHARACTERS = 10000;

export async function action({ request }: Route.ActionArgs): Promise<ActionData> {
  const formData = await request.formData();
  const textEntry = formData.get('text');

  // Validate input
  if (typeof textEntry !== 'string' || textEntry.length === 0) {
    return {
      error: 'Please enter some Japanese text.',
      originalText: '',
    };
  }

  if (textEntry.length > MAX_CHARACTERS) {
    return {
      error: `Text exceeds ${MAX_CHARACTERS} character limit.`,
      originalText: textEntry,
    };
  }

  try {
    const completion = await openaiClient.chat.completions.create({
      model: 'gpt-4o-mini',
      messages: [
        { role: 'system', content: FURIGANA_SYSTEM_PROMPT },
        { role: 'user', content: buildUserMessage(textEntry) },
      ],
      temperature: 0.3,
      max_tokens: textEntry.length * 3, // Accommodate readings
    });

    const annotationString = completion.choices[0]?.message?.content ?? '';

    if (!annotationString) {
      return {
        error: 'Something went wrong. Please try again.',
        originalText: textEntry,
      };
    }

    const tokens = parseAnnotationString(annotationString);

    return { tokens };
  } catch (error) {
    console.error('OpenAI API error:', error);
    return {
      error: 'Something went wrong. Please try again.',
      originalText: textEntry,
    };
  }
}
```

Key implementation notes:
- Uses `noUncheckedIndexedAccess`-safe access with optional chaining
- Generic error message to user; raw error logged server-side
- `temperature: 0.3` for consistent output format
- Returns parsed tokens, not raw annotationString (keeps parsing server-side)
- MAX_CHARACTERS constant for reuse

Create `app/components/furigana/InputArea.tsx`:

```typescript
// app/components/furigana/InputArea.tsx
import type { KeyboardEvent, ChangeEvent, RefObject } from 'react';

const MAX_CHARACTERS = 10000;

type InputAreaProps = {
  value: string;
  onChange: (value: string) => void;
  disabled: boolean;
  formRef: RefObject<HTMLFormElement | null>;
};

export function InputArea({ value, onChange, disabled, formRef }: InputAreaProps) {
  const characterCount = value.length;
  const isOverLimit = characterCount > MAX_CHARACTERS;
  const isEmpty = characterCount === 0;

  function handleChange(event: ChangeEvent<HTMLTextAreaElement>) {
    onChange(event.target.value);
  }

  function handleKeyDown(event: KeyboardEvent<HTMLTextAreaElement>) {
    if ((event.metaKey || event.ctrlKey) && event.key === 'Enter') {
      event.preventDefault();
      if (!isEmpty && !isOverLimit && !disabled) {
        formRef.current?.requestSubmit();
      }
    }
  }

  return (
    <div className="flex w-full flex-col gap-2">
      <textarea
        name="text"
        value={value}
        onChange={handleChange}
        onKeyDown={handleKeyDown}
        disabled={disabled}
        placeholder="Paste Japanese text here..."
        maxLength={MAX_CHARACTERS}
        aria-label="Japanese text input"
        className="min-h-[300px] w-full resize-y rounded-lg border border-input bg-background p-4 text-base leading-relaxed placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring disabled:cursor-not-allowed disabled:opacity-50"
      />
      <div className="flex justify-end">
        <span
          className={`text-sm ${isOverLimit ? 'text-destructive' : 'text-muted-foreground'}`}
        >
          {characterCount.toLocaleString()} / {MAX_CHARACTERS.toLocaleString()}
        </span>
      </div>
    </div>
  );
}
```

Key features:
- Controlled component with value/onChange props
- Cmd+Enter / Ctrl+Enter triggers form submission via requestSubmit()
- Character counter with warning color when over limit
- maxLength attribute prevents typing beyond limit
- Accessible with aria-label
- Uses shadcn/ui design tokens (border-input, text-muted-foreground, etc.)

