```typescript
// app/components/furigana/ReadingView.tsx
import type { FuriganaToken } from '~/lib/furigana/types';

type ReadingViewProps = {
  tokens: FuriganaToken[];
};

export function ReadingView({ tokens }: ReadingViewProps) {
  return (
    <article className="reading-view text-lg leading-[2.5] tracking-wide">
      {tokens.map((token, index) =>
        token.type === 'ruby' ? (
          <ruby key={index}>
            {token.kanji}
            <rp>(</rp>
            <rt>{token.reading}</rt>
            <rp>)</rp>
          </ruby>
        ) : (
          <span key={index}>{token.value}</span>
        ),
      )}
    </article>
  );
}
```

Key implementation notes:
- Uses semantic `<ruby>`, `<rt>`, `<rp>` elements (native HTML5)
- `<rp>` provides fallback parentheses for browsers without ruby support
- Token values are JSX interpolated (auto-escaped by React)
- NO `dangerouslySetInnerHTML` - completely XSS-safe
- Index-based keys are acceptable (array is immutable once rendered)
- `leading-[2.5]` provides generous line-height for ruby text
- Designed for future `viewMode` prop addition (Milestone 3)

CSS class `reading-view` can be used for additional styling hooks.

