Complete `app/routes/home.tsx` component:

```typescript
// app/routes/home.tsx (component portion)
import { useState, useRef, useEffect } from 'react';
import { Form, useNavigation, useActionData } from 'react-router';
import { Loader2 } from 'lucide-react';
import type { Route } from './+types/home';
import { Button } from '~/components/ui/button';
import { InputArea } from '~/components/furigana/InputArea';
import { ReadingView } from '~/components/furigana/ReadingView';
import type { ActionData } from './home'; // Import from same file

const MAX_CHARACTERS = 10000;

export function meta(_: Route.MetaArgs) {
  return [
    { title: 'Furigana - AI Japanese Reading Assistant' },
    { name: 'description', content: 'Add furigana readings to Japanese text with AI' },
  ];
}

export default function Home() {
  const actionData = useActionData<ActionData>();
  const navigation = useNavigation();
  const formRef = useRef<HTMLFormElement>(null);

  const isSubmitting = navigation.state === 'submitting';
  const hasTokens = actionData !== undefined && 'tokens' in actionData;
  const hasError = actionData !== undefined && 'error' in actionData;

  // Initialize text from error response to preserve user input
  const [text, setText] = useState(() => {
    if (hasError && actionData.originalText) {
      return actionData.originalText;
    }
    return '';
  });

  // Update text when error response changes (handles remount edge case)
  useEffect(() => {
    if (hasError && actionData.originalText) {
      setText(actionData.originalText);
    }
  }, [hasError, actionData]);

  const isOverLimit = text.length > MAX_CHARACTERS;
  const isEmpty = text.length === 0;
  const isSubmitDisabled = isSubmitting || isEmpty || isOverLimit;

  // Show ReadingView on success, InputArea otherwise
  if (hasTokens) {
    return (
      <main className="mx-auto flex min-h-screen max-w-3xl flex-col items-center justify-center gap-6 p-8">
        <h1 className="text-3xl font-bold">Furigana</h1>
        <ReadingView tokens={actionData.tokens} />
      </main>
    );
  }

  return (
    <main className="mx-auto flex min-h-screen max-w-3xl flex-col items-center justify-center gap-6 p-8">
      <h1 className="text-3xl font-bold">Furigana</h1>
      <p className="text-center text-muted-foreground">
        Paste Japanese text and get furigana readings instantly
      </p>

      <Form ref={formRef} method="post" className="flex w-full flex-col gap-4">
        <InputArea
          value={text}
          onChange={setText}
          disabled={isSubmitting}
          formRef={formRef}
        />

        {hasError && (
          <p role="alert" className="text-sm text-destructive">
            {actionData.error}
          </p>
        )}

        <Button type="submit" disabled={isSubmitDisabled} className="w-full">
          {isSubmitting ? (
            <>
              <Loader2 className="animate-spin" />
              Generating...
            </>
          ) : (
            'Generate Furigana'
          )}
        </Button>
      </Form>
    </main>
  );
}
```

Key implementation notes:
- Uses React Router's Form component for progressive enhancement
- useNavigation().state for loading state (idiomatic RR7)
- Error message has role="alert" for accessibility
- Text state preserved on error via useEffect
- Lucide Loader2 icon with animate-spin for spinner

