    const textarea = page.getByRole('textbox', { name: /japanese text/i });
    const originalText = '日本語';
    await textarea.fill(originalText);

    await page.getByRole('button', { name: /generate furigana/i }).click();

    // Wait for error message
    await expect(page.getByRole('alert')).toHaveText(/something went wrong/i, { timeout: 30000 });

